SELECT 'Данные успешно загружены!' AS status,
  (SELECT count(*) FROM courses) AS courses,
  (SELECT count(*) FROM modules) AS modules,
  (SELECT count(*) FROM quests) AS quests,
  (SELECT count(*) FROM library_resources) AS library,
  (SELECT count(*) FROM achievements) AS achievements,
  (SELECT count(*) FROM map_points) AS map_points,
  (SELECT count(*) FROM tourist_routes) AS routes;
