INSERT INTO courses (title, description, role, stage, image_url, total_modules, completed_modules, xp_reward, is_locked, category) VALUES
('Введение в туризм Владивостока', 'Погружение в туристическую экосистему Владивостока: история, ресурсы, потенциал. Вы становитесь начинающим гидом и изучаете город глазами туриста.', 'guide', 'Порт отправления', 'https://images.unsplash.com/photo-1578662996442-48f60103fc96?w=600', 5, 5, 200, false, 'Основы'),
('Туристический маркетинг и продвижение', 'Создание привлекательного образа Владивостока для туристов. Цифровой маркетинг, SMM, работа с блогерами и турагентствами.', 'marketer', 'Бухта открытий', 'https://images.unsplash.com/photo-1460925895917-afdab827c52f?w=600', 6, 2, 250, false, 'Маркетинг'),
('Разработка туристических маршрутов', 'Искусство создания незабываемых маршрутов. Логистика, бюджетирование, работа с поставщиками услуг и создание уникального опыта.', 'operator', 'Бухта открытий', 'https://images.unsplash.com/photo-1524661135-423995f22d0b?w=600', 7, 0, 300, false, 'Операционная деятельность'),
('Дизайн туристического продукта', 'Визуальная коммуникация в туризме. Брендинг направления, дизайн брошюр, веб-дизайн туристических ресурсов и фирменный стиль.', 'designer', 'Мост знаний', 'https://images.unsplash.com/photo-1561070791-2526d30994b5?w=600', 8, 0, 350, true, 'Дизайн'),
('Экотуризм и устойчивое развитие', 'Природный туризм Приморского края. Мыс Тобизина, национальные парки, морские заповедники. Ответственный подход к развитию территорий.', 'guide', 'Остров мастерства', 'https://images.unsplash.com/photo-1506905925346-21bda4d32df4?w=600', 6, 0, 400, true, 'Экотуризм'),
('Гастрономический туризм Приморья', 'Кулинарные традиции Владивостока: морепродукты, корейская и японская кухня, рестораторы-новаторы. Создание гастрономических туров.', 'operator', 'Тихоокеанский горизонт', 'https://images.unsplash.com/photo-1414235077428-338989a2e8c0?w=600', 5, 0, 350, true, 'Гастрономия');
