INSERT INTO quests (title, description, type, difficulty, xp_reward, is_completed, image_url, location_name) VALUES
('Маршрут по Золотому Рогу', 'Разработайте однодневный туристический маршрут по набережной Золотого Рога. Включите 5 ключевых достопримечательностей, рассчитайте время и транспортную логистику.', 'route', 'easy', 100, true, 'https://images.unsplash.com/photo-1569834382869-9d0e90b24e4d?w=500', 'Бухта Золотой Рог'),
('Бюджет тура на Русский остров', 'Составьте детальный бюджет трёхдневного тура на остров Русский для группы 15 человек. Учтите проживание, питание, транспорт и экскурсии.', 'budget', 'medium', 150, false, 'https://images.unsplash.com/photo-1524661135-423995f22d0b?w=500', 'Остров Русский'),
('SMM-кампания для Приморского сафари-парка', 'Создайте концепцию SMM-кампании для привлечения туристов в Приморский сафари-парк. Разработайте контент-план на месяц с хэштегами и форматами постов.', 'marketing', 'medium', 175, false, 'https://images.unsplash.com/photo-1551969014-7d2c4cddf0b6?w=500', 'Приморский сафари-парк'),
('Фирменный стиль гостиницы на мысе Тобизина', 'Разработайте концепцию визуального стиля для бутик-отеля на мысе Тобизина. Предложите цветовую палитру, логотип и ключевые элементы айдентики.', 'design', 'hard', 250, false, 'https://images.unsplash.com/photo-1561070791-2526d30994b5?w=500', 'Мыс Тобизина'),
('Гастрономический тур по Владивостоку', 'Составьте гастрономический маршрут по лучшим ресторанам Владивостока с морепродуктами. Включите историю блюд и рекомендации по времени посещения.', 'route', 'easy', 120, false, 'https://images.unsplash.com/photo-1414235077428-338989a2e8c0?w=500', 'Исторический центр'),
('Экомаршрут по Морскому заповеднику', 'Разработайте эко-тур по Дальневосточному морскому заповеднику с минимальным воздействием на природу. Включите образовательные элементы и правила поведения.', 'route', 'hard', 300, false, 'https://images.unsplash.com/photo-1506905925346-21bda4d32df4?w=500', 'Морской заповедник'),
('Рыбный рынок: морская дегустация', 'Посетите рыбный базар на набережной Спортивной гавани. Попробуйте минимум три вида местных морепродуктов (гребешок, морской ёж, трепанг). Сфотографируйте каждое блюдо и составьте краткое гастрономическое описание.', 'gastronomy', 'easy', 120, false, 'https://images.unsplash.com/photo-1553361371-9b22f78e8b1d?w=600', 'Набережная Спортивной гавани'),
('Маршрут по Миллионке', 'Исследуйте исторический квартал Миллионка (улицы Семёновская, Пограничная, Адмирала Фокина). Найдите и сфотографируйте три исторических доходных дома начала XX века с элементами китайской архитектуры. Укажите их адреса и опишите архитектурные особенности.', 'historical', 'medium', 200, false, 'https://images.unsplash.com/photo-1571168076754-d86d96748e74?w=600', 'Исторический квартал Миллионка'),
('Эко-маршрут на острове Русском', 'Пройдите пешком от кампуса ДВФУ до мыса Тобизина (7 км). Зафиксируйте в полевом дневнике 5 видов растений или птиц. Сфотографируйте лучший видовой пейзаж с пояснением к снимку.', 'ecology', 'hard', 300, false, 'https://images.unsplash.com/photo-1441974231531-c6227db76b6e?w=600', 'Остров Русский, мыс Тобизина'),
('Фестивальное ориентирование', 'Найдите информацию о ближайших культурных событиях Владивостока (Дальневосточный кинофестиваль, Тихоокеанский туристический форум, Восточный экономический форум). Составьте краткую афишу с датами, местами проведения и целевой аудиторией каждого.', 'cultural', 'easy', 100, false, 'https://images.unsplash.com/photo-1492684223066-81342ee5ff30?w=600', 'Конгрессно-выставочный центр «Точка»'),
('Дизайн туристического маршрута', 'Разработайте авторский 1-дневный маршрут для туристов из Японии или Кореи. Включите 5–7 точек (историческая достопримечательность, гастрономия, шопинг, природа). Учтите транспортную логистику и время на каждую локацию.', 'route', 'hard', 350, false, 'https://images.unsplash.com/photo-1524661135-423995f22d0b?w=600', 'Владивосток (центр)');
INSERT INTO library_resources (title, description, type, category, url, thumbnail_url, is_interactive) VALUES
('Основы туроперейтинга: анимированное руководство', 'Интерактивная презентация по ключевым процессам в работе туроператора: бронирование, логистика, работа с клиентами.', 'presentation', 'Операционная деятельность', '#', 'https://images.unsplash.com/photo-1460925895917-afdab827c52f?w=400', true),
('Инфографика: туристический поток Приморья 2024', 'Визуализация статистики туристических потоков в Приморский край за 2024 год с разбивкой по странам и сезонам.', 'infographic', 'Аналитика', '#', 'https://images.unsplash.com/photo-1551288049-bebda4e38f71?w=400', false),
('Видеолекция: история туризма на Дальнем Востоке', 'Документальная лекция о развитии туристической отрасли в Приморском крае от начала XX века до наших дней.', 'video', 'История', '#', 'https://images.unsplash.com/photo-1574492943744-cfb27680f7ce?w=400', false),
('Базы данных туристических ресурсов ЮНВТО', 'Доступ к исследованиям и статистике Всемирной туристической организации ООН по вопросам устойчивого туризма.', 'database', 'Международные организации', 'https://www.unwto.org', 'https://images.unsplash.com/photo-1454165804606-c3d57bc86b40?w=400', false),
('Интерактивный атлас природных ресурсов Приморья', 'Цифровой атлас с картами природных достопримечательностей, ООПТ и туристических зон Приморского края.', 'infographic', 'Экотуризм', '#', 'https://images.unsplash.com/photo-1506905925346-21bda4d32df4?w=400', true),
('Дизайн-мышление в туристическом бренде: методология и практика', 'Научная статья рассматривает применение методологии дизайн-мышления при формировании туристического бренда территории.', 'article', 'Дизайн', 'https://cyberleninka.ru/article/n/dizayn-myshlenie-v-turisticheskom-brende', 'https://images.unsplash.com/photo-1561070791-2526d30994b5?w=600', false),
('UX/UI в образовательных платформах: принципы визуальной навигации', 'Исследование посвящено принципам пользовательского опыта (UX) и интерфейсного дизайна (UI) в цифровых образовательных системах.', 'article', 'Дизайн', 'https://cyberleninka.ru/article/n/ux-ui-v-obrazovatelnykh-platformakh', 'https://images.unsplash.com/photo-1581291518857-4e27b48ff24e?w=600', false),
('Айдентика туристических дестинаций: от логотипа к экосистеме бренда', 'В статье исследуется эволюция визуальной идентичности туристических направлений — от единого логотипа до комплексной брендовой экосистемы.', 'article', 'Дизайн', 'https://cyberleninka.ru/article/n/aydentika-turisticheskikh-destinatsiy', 'https://images.unsplash.com/photo-1558655146-9f40138edfeb?w=600', false);
