INSERT INTO map_points (name, description, category, lat, lng, image_url, video_url, related_course_id, legend) VALUES
('Золотой мост', 'Вантовый мост через пролив Золотой Рог, ставший символом современного Владивостока. Открыт в 2012 году к саммиту АТЭС.', 'landmark', 43.115, 131.8855, 'https://images.unsplash.com/photo-1524661135-423995f22d0b?w=600', NULL, 1, 'По преданию, в водах Золотого Рога обитает дух-хранитель морских путей, который помогает кораблям в шторм найти дорогу домой.'),
('Морской вокзал', 'Главные морские ворота Владивостока, откуда отправляются паромы на острова и круизные лайнеры.', 'landmark', 43.1145, 131.8864, 'https://images.unsplash.com/photo-1578662996442-48f60103fc96?w=600', NULL, 3, NULL),
('Остров Русский', 'Крупнейший остров залива Петра Великого, где расположен Дальневосточный федеральный университет и парк «Берег тигра».', 'landmark', 43.0342, 131.9384, 'https://images.unsplash.com/photo-1569834382869-9d0e90b24e4d?w=600', NULL, 1, 'Остров хранит память о морских крепостных укреплениях XIX века, и в тихую ночь, говорят, можно услышать сигналы старинного маяка.'),
('Дальневосточный морской заповедник', 'Один из крупнейших морских заповедников России. Уникальная экосистема с морскими котиками, нерпами и редкими видами рыб.', 'nature', 42.6167, 131.1333, 'https://images.unsplash.com/photo-1506905925346-21bda4d32df4?w=600', NULL, 5, 'Рыбаки говорят, что в этих водах живёт добрый дух-нерпа, который показывает дорогу заблудившимся кораблям к берегу.'),
('Приморский музей им. Арсеньева', 'Главный краеведческий музей Приморья с коллекцией артефактов о природе и истории Дальнего Востока.', 'museum', 43.1156, 131.8831, 'https://images.unsplash.com/photo-1574492943744-cfb27680f7ce?w=600', NULL, 1, NULL),
('Мыс Тобизина', 'Живописный скалистый мыс на острове Русский с панорамным видом на Японское море. Популярное место для фото.', 'nature', 42.9744, 132.0081, 'https://images.unsplash.com/photo-1506905925346-21bda4d32df4?w=600', NULL, 5, 'По легенде, на рассвете первого дня года здесь можно загадать желание, связанное с морем, и оно обязательно сбудется.'),
('Набережная Спортивной гавани', 'Прогулочная набережная с видом на бухту. Ресторанная зона, яхт-клуб и отправная точка для морских прогулок.', 'landmark', 43.1138, 131.9017, 'https://images.unsplash.com/photo-1569834382869-9d0e90b24e4d?w=600', NULL, 6, NULL);
INSERT INTO tourist_routes (name, description, duration_hours, point_ids, difficulty, author_name, is_student_created) VALUES
('Путь первооткрывателя', 'Классический маршрут по историческому центру Владивостока: от Морского вокзала до Орлиного гнезда с видом на оба залива.', 4, ARRAY['1','2','5'], 'easy', 'Кафедра туризма ВВГУ', false),
('Острова и мосты', 'Захватывающий маршрут через Золотой мост на остров Русский с посещением ДВФУ и мыса Тобизина.', 8, ARRAY['1','3','6'], 'medium', 'Дмитрий Волков', true),
('Морской заповедник', 'Экологический маршрут к Дальневосточному морскому заповеднику. Наблюдение за морскими животными, подводный мир Японского моря.', 12, ARRAY['4','6'], 'hard', 'Анна Сизова', true);
